import{_ as l,o as a,c as i,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-07（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-07.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-07.md"}'),r={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-07.md"};function n(o,t,s,d,h,g){return a(),i("div",null,[...t[0]||(t[0]=[e(`<h1 id="🫘-黃豆追蹤日報-—-2026-05-07-週四" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-07（週四） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-07-週四" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-07（週四）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-07 05:00 TST（= 2026-05-06 21:00 UTC） ⚠️ 注意：05:00 TST = 17:00 ET（前日），CME 黃豆期貨 14:00-20:00 ET 為休息時段，以下為前日收盤及替代數據</p></blockquote><hr><h2 id="📊-即時價格" tabindex="-1">📊 即時價格 <a class="header-anchor" href="#📊-即時價格" aria-label="Permalink to &quot;📊 即時價格&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>價格</th><th>時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆期貨（May &#39;26, ZSK26）</td><td>1,178.25 USd/Bu（-1.46%）</td><td>2026-05-06</td><td>TradingEconomics</td></tr><tr><td>CBOT 黃豆期貨（前日收盤）</td><td>$11.95 3/4/bu（-11 3/4¢）</td><td>2026-05-05</td><td>Barchart</td></tr><tr><td>黃豆 CFD（前月）</td><td>+1.73%（月漲幅）、+14.34%（年漲幅）</td><td>2026-05-06</td><td>TradingEconomics</td></tr></tbody></table><hr><h2 id="🔍-8-項追蹤指標" tabindex="-1">🔍 8 項追蹤指標 <a class="header-anchor" href="#🔍-8-項追蹤指標" aria-label="Permalink to &quot;🔍 8 項追蹤指標&quot;">​</a></h2><h3 id="_1-🌱-usda-種植進度報告-每週" tabindex="-1">1. 🌱 USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-🌱-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. 🌱 USDA 種植進度報告（每週）&quot;">​</a></h3><p><strong>🔴 有重大變化 — 超前平均</strong></p><ul><li>截至 5/3，全美黃豆種植進度 <strong>33%</strong>，大幅超前五年平均 <strong>23%</strong></li><li>出芽率 <strong>13%</strong>（平均 5%）</li><li>路易斯安那 84%、密西西比 77%、阿肯色 73% 領先</li><li>內布拉斯加州 40%（超前平均 17%）</li><li>北部平原有低溫霜凍影響，且全美大范围降雨預報可能延緩後續播種</li><li><strong>下次報告</strong>：5/12</li><li>來源：DTN/USDA Crop Progress (2026-05-04)、Brownfield Ag News (2026-05-06)</li></ul><h3 id="_2-🇧🇷-巴西供應-收割-出口-豐收" tabindex="-1">2. 🇧🇷 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-🇧🇷-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 🇧🇷 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p><strong>🔴 有重大變化 — 產量上修、收割接近完成</strong></p><ul><li>StoneX 上修巴西 2025/26 產量預估至 <strong>1.816 億噸</strong>（+1%），創歷史紀錄</li><li>收割進度約 <strong>88.1%</strong>（截至 4 月底）</li><li>南大河州預估產量約 2,100 萬噸（儘管天候損失）</li><li><strong>挑戰</strong>：物流瓶頸（暴雨+乾旱）、與中國的植物檢疫爭議、國內壓榨需求增加（生物柴油政策）</li><li>來源：StoneX/Ukragroconsult (2026-05-01)、Revista Cultivar (2026-04)</li></ul><h3 id="_3-🧪-尿素價格-多單訊號-每月" tabindex="-1">3. 🧪 尿素價格 + 多單訊號（每月） <a class="header-anchor" href="#_3-🧪-尿素價格-多單訊號-每月" aria-label="Permalink to &quot;3. 🧪 尿素價格 + 多單訊號（每月）&quot;">​</a></h3><p><strong>🟡 價格高檔震盪</strong></p><ul><li>尿素現貨：<strong>577.50 USD/T</strong>（5/5，持平）</li><li>FOB 美灣 5 月期貨（JCK26）：<strong>623.00 USD/T</strong>（5/5）</li><li>世界銀行預測 2026 全球尿素價格可能飆漲 <strong>60%</strong>，有機會超過 2022 年均價 $700/T</li><li>霍爾木茲海峽危機推升化肥運輸成本與價格風險</li><li>NOLA 尿素 5 月現貨預估 <strong>$470-782/short ton</strong>（依海峽重開情景而定）</li><li>來源：TradingEconomics (2026-05-05)、Barchart (2026-05-05)、World Bank (2026-04)</li></ul><h3 id="_4-🚢-霍爾木茲海峽通航狀態-即時" tabindex="-1">4. 🚢 霍爾木茲海峽通航狀態（即時） <a class="header-anchor" href="#_4-🚢-霍爾木茲海峽通航狀態-即時" aria-label="Permalink to &quot;4. 🚢 霍爾木茲海峽通航狀態（即時）&quot;">​</a></h3><p><strong>🔴 高度不確定 — 實質仍受阻</strong></p><ul><li>伊朗革命衛隊宣稱將提供安全通行，但未提供具體程序</li><li>過去 48 小時海峽航行條件「急劇惡化」，<strong>470 艘船遭 GPS 干擾</strong>，AIS 大規模關閉</li><li>5/4 阿聯酋富查伊拉 VTTI 石油碼頭遭攻擊</li><li>法國船隻在海峽遇襲</li><li>美國暫停「Project Freedom」護航行動，但維持海上封鎖</li><li>數百艘船滞留波斯灣</li><li><strong>影響</strong>：全球約 20% 海上石油運輸受阻，推升運費與大宗商品運輸風險</li><li>來源：OPB (2026-05-06)、GTReview (2026-05-06)、CFR (2026-05-06)</li></ul><h3 id="_5-🇺🇸🇨🇳-中美貿易-中國進口-每月" tabindex="-1">5. 🇺🇸🇨🇳 中美貿易 + 中國進口（每月） <a class="header-anchor" href="#_5-🇺🇸🇨🇳-中美貿易-中國進口-每月" aria-label="Permalink to &quot;5. 🇺🇸🇨🇳 中美貿易 + 中國進口（每月）&quot;">​</a></h3><p><strong>🟡 有變化 — 5 月貿易談判在即</strong></p><ul><li>中國承諾 2026-2028 年每年進口至少 <strong>2,500 萬噸</strong>美國黃豆（比 2020-2024 平均少 14%）</li><li>美國黃豆協會（ASA）敦促取消中國剩餘 10% 關稅</li><li>2026 年前兩個月美國黃豆對中出口年增顯著，中國占美國黃豆總出口比重再度超過 50%</li><li>5 月中美貿易談判將是關鍵催化劑（原定會議因伊朗軍事行動延遲）</li><li>巴西預計仍是中國 2026 年最大供應國，進口量可能超過 1 億噸</li><li>來源：Brownfield Ag News (2026-05-06)、SeekingAlpha (2026-05-06)、Forbes (2026-04-24)</li></ul><h3 id="_6-🛢️-天然氣價格-每月" tabindex="-1">6. 🛢️ 天然氣價格（每月） <a class="header-anchor" href="#_6-🛢️-天然氣價格-每月" aria-label="Permalink to &quot;6. 🛢️ 天然氣價格（每月）&quot;">​</a></h3><p><strong>🟢 無重大變化</strong></p><ul><li>Henry Hub 天然氣：<strong>$2.72-2.745/MMBtu</strong>（5/6）</li><li>日跌 6.0 美分，短期天氣預報指向短暫寒流但影響有限</li><li>天然氣價格相對穩定，對黃豆生產成本影響中性</li><li>來源：TradingEconomics (2026-05-06)、NGI (2026-05-06)</li></ul><h3 id="_7-🌡️-聖嬰-拉尼娜氣候風險-每季" tabindex="-1">7. 🌡️ 聖嬰/拉尼娜氣候風險（每季） <a class="header-anchor" href="#_7-🌡️-聖嬰-拉尼娜氣候風險-每季" aria-label="Permalink to &quot;7. 🌡️ 聖嬰/拉尼娜氣候風險（每季）&quot;">​</a></h3><p><strong>🔴 有重大變化 — 即將進入聖嬰模式</strong></p><ul><li>全球氣候正從拉尼娜過渡至 <strong>聖嬰（El Niño）</strong>，預計 2026 年中形成並持續至年底甚至 2027</li><li>部分預測甚至警告可能出現「超級聖嬰」</li><li><strong>對黃豆影響</strong>：聖嬰通常有利全球黃豆產量（+2%~5%），為美國中西部、巴西南部、阿根廷帶來涼爽潮濕天氣</li><li><strong>風險</strong>：若聖嬰強度不足或時間偏移，巴西二作玉米可能受影響</li><li>來源：NOAA/CPC (2026-05)、Climate Impact Company (2026-05)、WMO (2026-02)</li></ul><h3 id="_8-📈-cbot-價格區間-每日" tabindex="-1">8. 📈 CBOT 價格區間（每日） <a class="header-anchor" href="#_8-📈-cbot-價格區間-每日" aria-label="Permalink to &quot;8. 📈 CBOT 價格區間（每日）&quot;">​</a></h3><p><strong>🟡 價格回落但仍在近期區間內</strong></p><ul><li>5/6 收盤：<strong>1,178.25 USd/Bu</strong>（-1.46%）</li><li>前日（5/5）收盤：<strong>$11.95 3/4/bu</strong></li><li>近期區間：$11.50-$12.00/bu（7 週高點附近）</li><li>TradingEconomics 預估本季末目標 <strong>1,197.95 USd/Bu</strong>，12 個月目標 <strong>1,251.18 USd/Bu</strong></li><li>來源：TradingEconomics (2026-05-06)、Barchart (2026-05-06)</li></ul><hr><h2 id="📰-即時黃豆新聞-5-條" tabindex="-1">📰 即時黃豆新聞 5 條 <a class="header-anchor" href="#📰-即時黃豆新聞-5-條" aria-label="Permalink to &quot;📰 即時黃豆新聞 5 條&quot;">​</a></h2><ol><li><p><strong>USDA 種植進度超前</strong>：全美黃豆種植 33%，超前五年平均 23%，路易斯安那 84% 領先（DTN/USDA, 2026-05-04）</p></li><li><p><strong>巴西 StoneX 上修產量至 1.816 億噸</strong>：收割 88.1% 接近完成，創歷史紀錄（Ukragroconsult, 2026-05-01）</p></li><li><p><strong>黃豆壓榨需求強勁</strong>：生物柴油政策推動豆油需求，USDA 上修農民均價至 $10.30/bu（SoyGrowers, 2026-04）</p></li><li><p><strong>霍爾木茲海峽危機推升豆油需求</strong>：原油價格高企增加生物柴油經濟效益，黃豆油受惠（Brownfield Ag News, 2026-05-06）</p></li><li><p><strong>中美 5 月貿易談判在即</strong>： grain traders 期待中國增購舊作黃豆，關稅減免是關鍵（Brownfield Ag News, 2026-05-06）</p></li></ol><hr><h2 id="🕐-美伊和談-48-小時窗口-5-7-11-00-tst-追加" tabindex="-1">🕐 美伊和談 48 小時窗口（5/7 11:00 TST 追加） <a class="header-anchor" href="#🕐-美伊和談-48-小時窗口-5-7-11-00-tst-追加" aria-label="Permalink to &quot;🕐 美伊和談 48 小時窗口（5/7 11:00 TST 追加）&quot;">​</a></h2><blockquote><p>戰爭第 <strong>69</strong> 天 | 停火第 <strong>30</strong> 天 | Trump 最後通牒時限：~48 小時</p></blockquote><h3 id="⏱-過去-72-小時急轉彎" tabindex="-1">⏱ 過去 72 小時急轉彎 <a class="header-anchor" href="#⏱-過去-72-小時急轉彎" aria-label="Permalink to &quot;⏱ 過去 72 小時急轉彎&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5/3-5/5 ── 美「自由專案」護航霍爾木茲 → UAE 遭襲 → 船隻起火</span></span>
<span class="line"><span>5/5 ──── Rubio 宣布史詩之怒已結束，Hegseth 稱停火仍有效</span></span>
<span class="line"><span>5/6 ──── ✅ 重大轉折：Trump 暫停自由專案，稱和談「取得巨大進展」</span></span>
<span class="line"><span>5/7 ──── ⚠️ Trump 最後通牒：48 小時內伊朗答覆，否則轟炸升級</span></span>
<span class="line"><span>          伊朗：仍在審查美方提案，將透過巴基斯坦回覆</span></span></code></pre></div><h3 id="📄-談判核心-14-點一頁備忘錄-mou" tabindex="-1">📄 談判核心：14 點一頁備忘錄（MoU） <a class="header-anchor" href="#📄-談判核心-14-點一頁備忘錄-mou" aria-label="Permalink to &quot;📄 談判核心：14 點一頁備忘錄（MoU）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">條款</th><th>內容</th><th style="text-align:left;">狀態</th></tr></thead><tbody><tr><td style="text-align:left;">戰爭終止</td><td>正式宣布結束戰爭</td><td style="text-align:left;">✅ 達成共識</td></tr><tr><td style="text-align:left;">30 天談判期</td><td>解決核問題、制裁、霍爾木茲</td><td style="text-align:left;">✅ 基礎上同意</td></tr><tr><td style="text-align:left;">濃縮鈾</td><td><strong>15 年</strong>暫停濃縮（美原要求 20 年）</td><td style="text-align:left;">⚠️ 差距縮小中</td></tr><tr><td style="text-align:left;">高濃鈾運出</td><td>伊朗將庫存運出國（可能運至美國）</td><td style="text-align:left;">🔴 上輪破局主因，未決</td></tr><tr><td style="text-align:left;">霍爾木茲</td><td>美伊各自解除封鎖</td><td style="text-align:left;">⚠️ 結構同意，細節未定</td></tr><tr><td style="text-align:left;">制裁解除</td><td>美解除制裁+解凍數十億資金</td><td style="text-align:left;">⚠️ 框架內，30 天談判</td></tr></tbody></table><h3 id="🎯-估價情境更新-5-7" tabindex="-1">🎯 估價情境更新（5/7） <a class="header-anchor" href="#🎯-估價情境更新-5-7" aria-label="Permalink to &quot;🎯 估價情境更新（5/7）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">情境</th><th style="text-align:right;">發生機率</th><th style="text-align:left;">CBOT 黃豆預期</th><th>傳導機制</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>和談簽署 MoU</strong></td><td style="text-align:right;"><strong>55-60%</strong></td><td style="text-align:left;"><strong>$10.50-11.50</strong></td><td>原油跌 → 生柴利潤崩 → 豆油降溫 → 黃豆回跌 → USDA WASDE $10.20 反而變準</td></tr><tr><td style="text-align:left;"><strong>協議破裂</strong></td><td style="text-align:right;"><strong>40-45%</strong></td><td style="text-align:left;"><strong>$12.50-14.00</strong></td><td>原油續飆 → 生柴爆衝 → 壓榨利潤新高 → 黃豆牛市情境兌現</td></tr><tr><td style="text-align:left;"><strong>僵持延續現狀</strong>（停火+封鎖）</td><td style="text-align:right;">20% 內</td><td style="text-align:left;">$11.50-12.50</td><td>中性延續，靜待 5/12 WASDE + 5/14 川習會</td></tr></tbody></table><h3 id="🔗-黃豆傳導鏈" tabindex="-1">🔗 黃豆傳導鏈 <a class="header-anchor" href="#🔗-黃豆傳導鏈" aria-label="Permalink to &quot;🔗 黃豆傳導鏈&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>和談成功：原油 ↓20-25% → 生柴經濟效益↓ → 豆油↓ → 壓榨利潤↓ → CBOT ↓</span></span>
<span class="line"><span>和談破裂：原油 ↑15-25% → 生柴持續發燒 → 豆油↑ → 壓榨創紀錄 → CBOT 飆</span></span></code></pre></div><p><strong>5/12 USDA WASDE 與 5/14 川習會之前，最大變數不是 USDA 也不是中國——是這 48 小時內的伊朗答覆。</strong></p><h3 id="📡-關鍵即時資料點-5-6-5-7" tabindex="-1">📡 關鍵即時資料點（5/6-5/7） <a class="header-anchor" href="#📡-關鍵即時資料點-5-6-5-7" aria-label="Permalink to &quot;📡 關鍵即時資料點（5/6-5/7）&quot;">​</a></h3><ul><li>Trump Truth Social：「If they don&#39;t agree, the bombing starts, and it will be, sadly, at a much higher level and intensity than it was before.」他自承「a big assumption」</li><li>伊朗革命衛隊成立「波斯灣海峽管理局」，永久改變霍爾木茲地位，非暫時措施</li><li>IRGC 表示「美軍威脅結束後、新程序到位後即恢復安全通航」</li><li>巴基斯坦總理 Sharif 公開感謝 Trump 暫停自由專案，稱有助「區域和平、穩定與和解」</li><li>法國 CMA CGM 貨櫃船 San Antonio 號仍在霍爾木茲被攻擊，安全形勢未實質改善</li><li>中國外長王毅見伊朗外長：「全面停止敵對行動刻不容緩，重啟戰爭更不可取」</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-06): 黃豆期貨 1,178.25 USd/Bu</li><li>Barchart (2026-05-06): ZSK26 合約報價</li><li>DTN/USDA (2026-05-04): 種植進度 33%</li><li>StoneX/Ukragroconsult (2026-05-01): 巴西產量上修至 1.816 億噸</li><li>TradingEconomics (2026-05-05): 尿素 577.50 USD/T</li><li>World Bank (2026-04): 尿素價格預測</li><li>OPB/CFR (2026-05-06): 霍爾木茲海峽通航狀態</li><li>Brownfield Ag News (2026-05-06): 中美貿易談判</li><li>NOAA/CPC (2026-05): 聖嬰發展預測</li><li>NGI (2026-05-06): 天然氣 $2.72-2.745/MMBtu</li></ol>`,51)])])}const p=l(r,[["render",n]]);export{u as __pageData,p as default};
